use crate::types::{DecideInput, DecideOutput};
use std::f64::consts::PI;

#[derive(Clone, Copy)]
struct Point {
    x: f64,
    y: f64,
}

pub fn decide(input: &DecideInput) -> DecideOutput {
    let points: Vec<Point> = (0..input.numpoints)
        .map(|i| Point {
            x: input.x[i],
            y: input.y[i],
        })
        .collect();
    let params = &input.parameters;

    let mut cmv = [false; 15];
    cmv[0] = lic1(&points, params.length1);
    cmv[1] = lic2(&points, params.radius1);
    cmv[2] = lic3(&points, params.epsilon);
    cmv[3] = lic4(&points, params.area1);
    cmv[4] = lic5(&points, params.q_pts, params.quads);
    cmv[5] = lic6(&points);
    cmv[6] = lic7(&points, params.n_pts, params.dist);
    cmv[7] = lic8(&points, params.k_pts, params.length1);
    cmv[8] = lic9(&points, params.a_pts, params.b_pts, params.radius1);
    cmv[9] = lic10(&points, params.c_pts, params.d_pts, params.epsilon);
    cmv[10] = lic11(&points, params.e_pts, params.f_pts, params.area1);
    cmv[11] = lic12(&points, params.g_pts);
    cmv[12] = lic13(&points, params.k_pts, params.length1, params.length2);
    cmv[13] = lic14(
        &points,
        params.a_pts,
        params.b_pts,
        params.radius1,
        params.radius2,
    );
    cmv[14] = lic15(
        &points,
        params.e_pts,
        params.f_pts,
        params.area1,
        params.area2,
    );

    let mut pum = vec![vec![true; 15]; 15];
    for i in 0..15 {
        pum[i][i] = input.pum_diag[i];
        for j in 0..15 {
            if i == j {
                continue;
            }
            pum[i][j] = match input.lcm[i][j].as_str() {
                "NOTUSED" => true,
                "ANDD" => cmv[i] && cmv[j],
                "ORR" => cmv[i] || cmv[j],
                _ => true,
            };
        }
    }

    let mut fuv = vec![false; 15];
    for i in 0..15 {
        if !input.pum_diag[i] {
            fuv[i] = true;
        } else if pum[i].iter().all(|&value| value) {
            fuv[i] = true;
        }
    }

    let launch = fuv.iter().all(|&value| value);

    DecideOutput {
        cmv: cmv.to_vec(),
        pum,
        fuv,
        launch,
    }
}

fn lic1(points: &[Point], length1: f64) -> bool {
    if points.len() < 2 {
        return false;
    }
    for pair in points.windows(2) {
        if real_gt(distance(pair[0], pair[1]), length1) {
            return true;
        }
    }
    false
}

fn lic2(points: &[Point], radius1: f64) -> bool {
    if points.len() < 3 {
        return false;
    }
    for triple in points.windows(3) {
        if !can_be_contained(triple[0], triple[1], triple[2], radius1) {
            return true;
        }
    }
    false
}

fn lic3(points: &[Point], epsilon: f64) -> bool {
    if points.len() < 3 {
        return false;
    }
    for triple in points.windows(3) {
        if forms_invalid_angle(triple[0], triple[1], triple[2], epsilon) {
            return true;
        }
    }
    false
}

fn lic4(points: &[Point], area1: f64) -> bool {
    if points.len() < 3 {
        return false;
    }
    for triple in points.windows(3) {
        if real_gt(triangle_area(triple[0], triple[1], triple[2]), area1) {
            return true;
        }
    }
    false
}

fn lic5(points: &[Point], q_pts: usize, quads: usize) -> bool {
    if q_pts == 0 || points.len() < q_pts {
        return false;
    }
    for window in points.windows(q_pts) {
        let mut quadrant_hits = [false; 4];
        for point in window {
            let quad = quadrant(*point);
            quadrant_hits[quad] = true;
        }
        let count = quadrant_hits.iter().filter(|&&hit| hit).count();
        if count > quads {
            return true;
        }
    }
    false
}

fn lic6(points: &[Point]) -> bool {
    if points.len() < 2 {
        return false;
    }
    for pair in points.windows(2) {
        if real_lt(pair[1].x - pair[0].x, 0.0) {
            return true;
        }
    }
    false
}

fn lic7(points: &[Point], n_pts: usize, dist: f64) -> bool {
    if n_pts < 3 || points.len() < n_pts {
        return false;
    }
    for start in 0..=points.len() - n_pts {
        let first = points[start];
        let last = points[start + n_pts - 1];
        let identical_endpoints = same_point(first, last);
        for idx in start..=start + n_pts - 1 {
            let point = points[idx];
            let distance_value = if identical_endpoints {
                distance(point, first)
            } else {
                distance_to_line(point, first, last)
            };
            if real_gt(distance_value, dist) {
                return true;
            }
        }
    }
    false
}

fn lic8(points: &[Point], k_pts: usize, length1: f64) -> bool {
    if points.len() < 3 || points.len() <= k_pts + 1 {
        return false;
    }
    for start in 0..(points.len() - k_pts - 1) {
        let end = start + k_pts + 1;
        if real_gt(distance(points[start], points[end]), length1) {
            return true;
        }
    }
    false
}

fn lic9(points: &[Point], a_pts: usize, b_pts: usize, radius1: f64) -> bool {
    if points.len() < 5 {
        return false;
    }
    let needed = a_pts + b_pts + 2;
    if points.len() <= needed {
        return false;
    }
    for first in 0..(points.len() - needed) {
        let second = first + a_pts + 1;
        let third = second + b_pts + 1;
        if !can_be_contained(points[first], points[second], points[third], radius1) {
            return true;
        }
    }
    false
}

fn lic10(points: &[Point], c_pts: usize, d_pts: usize, epsilon: f64) -> bool {
    if points.len() < 5 {
        return false;
    }
    let needed = c_pts + d_pts + 2;
    if points.len() <= needed {
        return false;
    }
    for first in 0..(points.len() - needed) {
        let second = first + c_pts + 1;
        let third = second + d_pts + 1;
        if forms_invalid_angle(points[first], points[second], points[third], epsilon) {
            return true;
        }
    }
    false
}

fn lic11(points: &[Point], e_pts: usize, f_pts: usize, area1: f64) -> bool {
    if points.len() < 5 {
        return false;
    }
    let needed = e_pts + f_pts + 2;
    if points.len() <= needed {
        return false;
    }
    for first in 0..(points.len() - needed) {
        let second = first + e_pts + 1;
        let third = second + f_pts + 1;
        if real_gt(
            triangle_area(points[first], points[second], points[third]),
            area1,
        ) {
            return true;
        }
    }
    false
}

fn lic12(points: &[Point], g_pts: usize) -> bool {
    if points.len() < 3 || points.len() <= g_pts + 1 {
        return false;
    }
    for first in 0..(points.len() - g_pts - 1) {
        let second = first + g_pts + 1;
        if real_lt(points[second].x - points[first].x, 0.0) {
            return true;
        }
    }
    false
}

fn lic13(points: &[Point], k_pts: usize, length1: f64, length2: f64) -> bool {
    if points.len() < 3 || points.len() <= k_pts + 1 {
        return false;
    }
    let mut longer_found = false;
    let mut shorter_found = false;
    for first in 0..(points.len() - k_pts - 1) {
        let second = first + k_pts + 1;
        let dist_value = distance(points[first], points[second]);
        if !longer_found && real_gt(dist_value, length1) {
            longer_found = true;
        }
        if !shorter_found && real_lt(dist_value, length2) {
            shorter_found = true;
        }
        if longer_found && shorter_found {
            return true;
        }
    }
    false
}

fn lic14(points: &[Point], a_pts: usize, b_pts: usize, radius1: f64, radius2: f64) -> bool {
    if points.len() < 5 {
        return false;
    }
    let needed = a_pts + b_pts + 2;
    if points.len() <= needed {
        return false;
    }
    let mut part_one = false;
    let mut part_two = false;
    for first in 0..(points.len() - needed) {
        let second = first + a_pts + 1;
        let third = second + b_pts + 1;
        if !part_one && !can_be_contained(points[first], points[second], points[third], radius1) {
            part_one = true;
        }
        if !part_two && can_be_contained(points[first], points[second], points[third], radius2) {
            part_two = true;
        }
        if part_one && part_two {
            return true;
        }
    }
    false
}

fn lic15(points: &[Point], e_pts: usize, f_pts: usize, area1: f64, area2: f64) -> bool {
    if points.len() < 5 {
        return false;
    }
    let needed = e_pts + f_pts + 2;
    if points.len() <= needed {
        return false;
    }
    let mut large_area_found = false;
    let mut small_area_found = false;
    for first in 0..(points.len() - needed) {
        let second = first + e_pts + 1;
        let third = second + f_pts + 1;
        let area_value = triangle_area(points[first], points[second], points[third]);
        if !large_area_found && real_gt(area_value, area1) {
            large_area_found = true;
        }
        if !small_area_found && real_lt(area_value, area2) {
            small_area_found = true;
        }
        if large_area_found && small_area_found {
            return true;
        }
    }
    false
}

fn distance(a: Point, b: Point) -> f64 {
    let dx = a.x - b.x;
    let dy = a.y - b.y;
    (dx * dx + dy * dy).sqrt()
}

fn triangle_area(a: Point, b: Point, c: Point) -> f64 {
    let area = a.x * (b.y - c.y) + b.x * (c.y - a.y) + c.x * (a.y - b.y);
    0.5 * area.abs()
}

fn distance_to_line(p: Point, a: Point, b: Point) -> f64 {
    let dx = b.x - a.x;
    let dy = b.y - a.y;
    if real_eq(dx, 0.0) && real_eq(dy, 0.0) {
        return distance(p, a);
    }
    let numerator = ((dy) * (p.x - a.x) - (dx) * (p.y - a.y)).abs();
    let denominator = (dx * dx + dy * dy).sqrt();
    if real_eq(denominator, 0.0) {
        distance(p, a)
    } else {
        numerator / denominator
    }
}

fn can_be_contained(p1: Point, p2: Point, p3: Point, radius: f64) -> bool {
    let required_radius = minimal_enclosing_radius(p1, p2, p3);
    real_le(required_radius, radius)
}

fn minimal_enclosing_radius(p1: Point, p2: Point, p3: Point) -> f64 {
    let d12 = distance(p1, p2);
    let d23 = distance(p2, p3);
    let d31 = distance(p3, p1);
    let area = triangle_area(p1, p2, p3);
    if real_eq(area, 0.0) {
        let max_dist = real_max(d12, real_max(d23, d31));
        max_dist / 2.0
    } else {
        (d12 * d23 * d31) / (4.0 * area)
    }
}

fn forms_invalid_angle(p1: Point, vertex: Point, p3: Point, epsilon: f64) -> bool {
    let v1 = (p1.x - vertex.x, p1.y - vertex.y);
    let v2 = (p3.x - vertex.x, p3.y - vertex.y);
    let len1 = (v1.0 * v1.0 + v1.1 * v1.1).sqrt();
    let len2 = (v2.0 * v2.0 + v2.1 * v2.1).sqrt();
    if real_eq(len1, 0.0) || real_eq(len2, 0.0) {
        return false;
    }
    let dot = v1.0 * v2.0 + v1.1 * v2.1;
    let denom = len1 * len2;
    if real_eq(denom, 0.0) {
        return false;
    }
    let mut cos_value = dot / denom;
    if real_gt(cos_value, 1.0) {
        cos_value = 1.0;
    } else if real_lt(cos_value, -1.0) {
        cos_value = -1.0;
    }
    let angle = cos_value.acos();
    let lower = PI - epsilon;
    let upper = PI + epsilon;
    real_lt(angle, lower) || real_gt(angle, upper)
}

fn quadrant(point: Point) -> usize {
    if real_ge(point.x, 0.0) && real_ge(point.y, 0.0) {
        0
    } else if real_lt(point.x, 0.0) && real_ge(point.y, 0.0) {
        1
    } else if real_le(point.x, 0.0) && real_lt(point.y, 0.0) {
        2
    } else {
        3
    }
}

fn same_point(a: Point, b: Point) -> bool {
    real_eq(a.x, b.x) && real_eq(a.y, b.y)
}

fn real_max(a: f64, b: f64) -> f64 {
    if real_gt(a, b) {
        a
    } else {
        b
    }
}

fn real_lt(a: f64, b: f64) -> bool {
    realcompare(a, b) == "LT"
}

fn real_gt(a: f64, b: f64) -> bool {
    realcompare(a, b) == "GT"
}

fn real_eq(a: f64, b: f64) -> bool {
    realcompare(a, b) == "EQ"
}

fn real_le(a: f64, b: f64) -> bool {
    let cmp = realcompare(a, b);
    cmp == "LT" || cmp == "EQ"
}

fn real_ge(a: f64, b: f64) -> bool {
    let cmp = realcompare(a, b);
    cmp == "GT" || cmp == "EQ"
}

fn realcompare(a: f64, b: f64) -> &'static str {
    let mut rounded_a = round_to_significant_digits(a, 6);
    let mut rounded_b = round_to_significant_digits(b, 6);
    if rounded_a == -0.0 {
        rounded_a = 0.0;
    }
    if rounded_b == -0.0 {
        rounded_b = 0.0;
    }
    if rounded_a < rounded_b {
        "LT"
    } else if rounded_a > rounded_b {
        "GT"
    } else {
        "EQ"
    }
}

fn round_to_significant_digits(value: f64, digits: i32) -> f64 {
    if value == 0.0 || !value.is_finite() {
        return value;
    }
    let abs_value = value.abs();
    let exponent = abs_value.log10().floor() as i32;
    let scale = 10f64.powi(exponent - digits + 1);
    if scale == 0.0 || !scale.is_finite() {
        return value;
    }
    (value / scale).round() * scale
}
